import{_ as t}from"./chunks/logo.PPNoggWL.js";import{_ as i,o as a,c as e,ag as o}from"./chunks/framework.wGDfT7ie.js";const k=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"doc","next":{"text":"Post-Installation","link":"/pages/installation/post-installation"},"prev":{"text":"Installation Guide","link":"/pages/installation/index"}},"headers":[],"relativePath":"pages/installation/troubleshooting.md","filePath":"pages/installation/troubleshooting.md"}'),n={name:"pages/installation/troubleshooting.md"};function l(r,s,p,h,d,c){return a(),e("div",null,[...s[0]||(s[0]=[o('<img src="'+t+`" alt="AtmosphericX Logo" width="200" style="display:block;margin-left:auto;margin-right:auto;"><small class="page-author">Written By: KiyoWx &amp; StarflightWx</small><br><small class="last-updated">Last Updated: Jan 23rd, 2026</small><h2 id="troubleshooting-installation-issues" tabindex="-1">Troubleshooting Installation Issues <a class="header-anchor" href="#troubleshooting-installation-issues" aria-label="Permalink to &quot;Troubleshooting Installation Issues&quot;">​</a></h2><p>If you have successfully followed the installation steps but are encountering issues, this section provides solutions to common problems that may arise during the installation process. Please be sure to read through each potential issue and its corresponding solution. If your specific issue is not listed here, consider reaching out to the community on our <a href="https://discord.gg/YAEjtzU3E8" target="_blank" rel="noreferrer">Discord server</a> for further assistance. Please provide as much detail as possible about the problem you are facing and be aware that support is limited and mostly volunteer based.</p><p>If you are not encountering any issues, you may proceed to the <a href="./accounts.html">post-installation setup</a> guide to continue setting up AtmosphericX.</p><div class="tip custom-block"><p class="custom-block-title">Please read before troubleshooting</p><p>Before you start troubleshooting, confirm you&#39;ve completed every step in the <a href="./index.html">Installation Guide</a>. This list is not exhaustive and some fixes may not apply to every environment. Many items address Windows specific problems, so macOS and Linux users may not encounter them.</p></div><h2 id="common-issues-and-solutions" tabindex="-1">Common Issues and Solutions <a class="header-anchor" href="#common-issues-and-solutions" aria-label="Permalink to &quot;Common Issues and Solutions&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">1. VS not looking for VS2017 (<a href="https://github.com/AtmosphericX/AtmosphericX/issues/61" target="_blank" rel="noreferrer">Issue #61</a>)</p><p>During installation, the process fails because it cannot find the Visual C++ Redistributable for Visual Studio 2017 or later.</p><ol><li>Download the latest supported Visual C++ Redistributable from Microsoft:<br><a href="https://learn.microsoft.com/en-us/cpp/windows/latest-supported-vc-redist?view=msvc-170" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/cpp/windows/latest-supported-vc-redist?view=msvc-170</a></li><li>Install the appropriate package(s) for your system (x64 / x86).</li><li>Re-run the AtmosphericX installation.</li></ol><p>If you still face issues, specifically with <code>better-sqlite3</code> during installation. Consider looking at <a href="https://github.com/WiseLibs/better-sqlite3/blob/master/docs/troubleshooting.md" target="_blank" rel="noreferrer">this guide</a> for additional help.</p></div><div class="danger custom-block"><p class="custom-block-title">2. Python not found during installation</p><p>During the installation, the process fails because it cannot find Python 3.8 or newer. Please ensure Python is installed and added to your system PATH.</p><ol><li>Install <strong>Python 3.8 or newer</strong> from:<br><a href="https://www.python.org/downloads/" target="_blank" rel="noreferrer">https://www.python.org/downloads/</a></li><li>During installation, ensure <strong>“Add Python to PATH”</strong> is checked.</li><li>Open a new terminal and verify Python is available:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># or...</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div></li><li>Re-run the AtmosphericX installation.</li></ol></div><div class="danger custom-block"><p class="custom-block-title">3. Port 80 already in use</p><p>When starting AtmosphericX, it fails to bind to port 80 because another application is already using it or insufficient permissions.</p><ol><li>Identify the application using port 80:</li></ol><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-wrf_P" id="tab-6gow0A6" checked><label data-title="Windows" for="tab-6gow0A6">Windows</label><input type="radio" name="group-wrf_P" id="tab-sLbJr5E"><label data-title="Linux/macOS" for="tab-sLbJr5E">Linux/macOS</label><input type="radio" name="group-wrf_P" id="tab-WdDMUZW"><label data-title="Linux Elevated Start" for="tab-WdDMUZW">Linux Elevated Start</label></div><div class="blocks"><div class="language-sh vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">netstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -aon</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> findstr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :80</span></span></code></pre></div><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lsof</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :80</span></span></code></pre></div><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build-tools</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run.sh</span></span></code></pre></div><ol start="2"><li>Stop the conflicting application or change its port.</li></ol></div></div></div><div class="danger custom-block"><p class="custom-block-title">4. Instant Closure on Start</p><p>AtmosphericX starts but immediately exits without errors. . Run AtmosphericX from a terminal to instead of double-clicking the script. This way, you can see any error messages.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build-tools</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run.sh</span></span></code></pre></div><ol start="2"><li>Check the terminal output for errors and address them accordingly.</li><li>If the issue persists, consider reaching out on our <a href="https://discord.gg/YAEjtzU3E8" target="_blank" rel="noreferrer">Discord server</a> for further assistance. Please make sure to include any error logs or messages you encounter.</li></ol></div>`,13)])])}const m=i(n,[["render",l]]);export{k as __pageData,m as default};
